function toObjectLiteral(obj) {
  const entries = Object.entries(obj).map(([key, value]) => {
    const valueStr = typeof value === "string" ? `"${value}"` : value;
    return `${key}: ${valueStr}`;
  });
  return `{ ${entries.join(", ")} }`;
}
